#!/usr/bin/env node
/**
 * Snapshot the agent_platform OpenAPI schema into agent-console.
 *
 * Why: the Django side is the source of truth for the wire shape — it
 * lives in `products/agent_platform/frontend/generated/api.schemas.ts` and
 * is regenerated by `hogli build:openapi`. The console consumes those
 * types in `apiClient.ts`, but we don't want a hard import across
 * packages (Docker builds shouldn't need the rest of the monorepo on
 * disk to type-check). So we copy the file in at codegen time and the
 * console always imports its local copy.
 *
 * The local copy is committed to source control. Re-run this script
 * after any change to the agent_platform serializers (or just run
 * `hogli build:openapi`, which calls it as a step).
 */

import { promises as fs } from 'node:fs'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const HERE = path.dirname(fileURLToPath(import.meta.url))
const CONSOLE_ROOT = path.resolve(HERE, '..')
const REPO_ROOT = path.resolve(CONSOLE_ROOT, '../..')

const SOURCES = [
    {
        from: path.join(REPO_ROOT, 'products/agent_platform/frontend/generated/api.schemas.ts'),
        to: path.join(CONSOLE_ROOT, 'src/generated/agent-platform.api.schemas.ts'),
    },
]

const HEADER = `/**
 * ⚠️ GENERATED — do not edit.
 *
 * Snapshot of the agent_platform OpenAPI types, copied from
 * products/agent_platform/frontend/generated/api.schemas.ts by
 * services/agent-console/bin/sync-api-schema.mjs.
 *
 * Re-run \`hogli build:openapi\` (or directly:
 * \`pnpm --filter=@posthog/agent-console sync:api-schema\`) to refresh.
 */
/* eslint-disable */
// @ts-nocheck — generated upstream; types are exercised by the importing apiClient.

`

async function main() {
    for (const { from, to } of SOURCES) {
        const raw = await fs.readFile(from, 'utf8')
        await fs.mkdir(path.dirname(to), { recursive: true })
        await fs.writeFile(to, HEADER + raw, 'utf8')
        const rel = path.relative(REPO_ROOT, to)
        process.stdout.write(`sync-api-schema: wrote ${rel}\n`)
    }
}

main().catch((err) => {
    process.stderr.write(`sync-api-schema failed: ${err.message}\n`)
    process.exit(1)
})
